import "math"

// DSU structure specialized for maintaining relative path parity (XOR differences)
type DSU struct {
	parent []int64
	// rank is used for union by rank optimization
	rank []int64
	// diff[i] stores the parity (0 or 1) of the path weight from node i to its immediate parent[i]
	diff []int64
}

func NewDSU(n int64) *DSU {
	dsu := &DSU{
		parent: make([]int64, n),
		rank:   make([]int64, n),
		diff:   make([]int64, n),
	}
	for i := int64(0); i < n; i++ {
		dsu.parent[i] = i
		dsu.rank[i] = 0
		dsu.diff[i] = 0 // Parity from node i to itself (root) is 0
	}
	return dsu
}

// Find returns the root of the set containing i, and the parity of the path weight from i to the root.
func (d *DSU) Find(i int64) (root int64, parityToRoot int64) {
	if d.parent[i] == i {
		return i, 0
	}

	// Recursive call to find the actual root and parity of the parent path
	root, parityFromParentToRoot := d.Find(d.parent[i])

	// Path compression: update parent of i to be the root
	// Update diff[i]: New parity = (i -> old_parent) XOR (old_parent -> root)
	d.diff[i] = d.diff[i] ^ parityFromParentToRoot
	d.parent[i] = root

	return root, d.diff[i]
}

// Union attempts to connect nodes u and v with an edge of weight w.
// Returns true if the edge is added (i.e., it does not create an odd cycle), false otherwise.
func (d *DSU) Union(u, v, w int64) bool {
	rootU, parityU := d.Find(u)
	rootV, parityV := d.Find(v)

	if rootU == rootV {
		// u and v are already in the same component. Adding the edge creates a cycle.
		// Cycle weight = (u -> root) XOR (v -> root) XOR w
		// Since path parities are stored relative to the root:
		// Path u <-> v weight parity in tree = parityU ^ parityV
		// New cycle parity = (parityU ^ parityV) ^ w

		cycleParity := parityU ^ parityV ^ w

		// We only add the edge if the cycle weight is EVEN (cycleParity == 0)
		return cycleParity == 0
	}

	// Roots are different. Merge the sets.

	// Union by rank heuristic
	if d.rank[rootU] < d.rank[rootV] {
		rootU, rootV = rootV, rootU
		parityU, parityV = parityV, parityU
	}

	// Attach rootV to rootU
	d.parent[rootV] = rootU

	// Determine the required parity diff[rootV] (path from rootV to rootU)
	// Path: rootV --(parityV)--> v --(w)--> u --(parityU)--> rootU
	// Parity(rootV -> rootU) = Parity(rootV -> v) ^ Parity(v -> u) ^ Parity(u -> rootU)
	// Parity(rootV -> v) == parityV (since XOR is symmetric)
	// Parity(v -> u) == w
	// Parity(u -> rootU) == parityU
	d.diff[rootV] = parityV ^ w ^ parityU

	if d.rank[rootU] == d.rank[rootV] {
		d.rank[rootU]++
	}

	return true
}

func solve(n int64, edges [][]int64) int64 {
	dsu := NewDSU(n)
	acceptedEdgesCount := int64(0)

	for _, edge := range edges {
		u := edge[0]
		v := edge[1]
		w := edge[2]

		if dsu.Union(u, v, w) {
			acceptedEdgesCount++
		}
	}

	return acceptedEdgesCount
}
