		return i, 0
	}

	// Recursive call to find the root and the distance of the parent to the root
	root, parentDist := d.Find(d.parent[i])

	// Path compression: update distance[i] based on the distance of parent[i] to root
	// New distance = (i -> parent[i]) XOR (parent[i] -> root)
	d.dist[i] = (d.dist[i] + parentDist) % 2
	d.parent[i] = root

	return root, d.dist[i]
